<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import { useRoute } from 'vue-router'
import { useQuery } from '@tanstack/vue-query'
import { BookmarkCheck, Clock3, PlayCircle } from '@lucide/vue'
import { api, handlePosterError, posterURL } from '../api/client'
import AsyncButton from '../components/AsyncButton.vue'
import PageHeader from '../components/PageHeader.vue'
import StateBlock from '../components/StateBlock.vue'
import { useAsyncActions } from '../composables/useAsyncActions'
import { useUIStore } from '../stores/ui'

interface Episode { id:number; name:string; episode:number; season:number; playable:boolean; thumbnail:string; overview:string; duration:string; watched?:boolean }
interface Payload { anime:{ID:number;title:string;summary:string;image:string;metadata?:{title_cn?:string;image?:string;summary?:string;bangumi_id?:number}};episodes:Episode[];collection_status?:{bangumi_watched_count:number;anilist_watched_count:number} }
const route=useRoute(),ui=useUIStore(),actions=useAsyncActions(),animeId=computed(()=>Number(route.query.anime||0)),selected=ref<Episode|null>(null),progress=ref(0)
const query=useQuery({queryKey:['episodes',animeId],queryFn:()=>api<Payload>(`/local-anime/${animeId.value}/episodes`),enabled:computed(()=>animeId.value>0)})
watch(()=>query.data.value?.episodes,episodes=>{selected.value=episodes?.find(item=>item.playable)||episodes?.[0]||null;progress.value=query.data.value?.collection_status?.bangumi_watched_count||0},{immediate:true})
const play=(id:number)=>`/api/v1/jellyfin/stream/${id}`
async function syncProgress(){const bangumiID=query.data.value?.anime.metadata?.bangumi_id;if(!bangumiID)return;try{await actions.run('sync-progress',async()=>{await api(`/bangumi/subject/${bangumiID}/progress`,{method:'POST',body:JSON.stringify({episode_count:progress.value}),headers:{'Content-Type':'application/json'}});ui.toast(`已同步至第 ${progress.value} 集`)})}catch(e){ui.toast(e instanceof Error?e.message:'同步失败','error')}}
</script>

<template><div class="page-grid"><PageHeader eyebrow="WATCH" title="播放工作区" description="从本地媒体库选择剧集，在一个工作区内播放并同步观看进度。"/><StateBlock v-if="!animeId" state="empty" title="请先选择一部本地番剧" description="在本地番剧页点击“查看与播放”进入这里。"/><StateBlock v-else-if="query.isLoading.value" state="loading"/><StateBlock v-else-if="query.isError.value" state="error" title="无法读取剧集" :retrying="query.isFetching.value" @retry="query.refetch()"/><template v-else-if="query.data.value"><section class="panel overflow-hidden"><div class="grid gap-6 p-5 lg:grid-cols-[220px_1fr]"><img :src="posterURL(query.data.value.anime.metadata||{image:query.data.value.anime.image})" :alt="query.data.value.anime.title" class="aspect-[2/3] w-full max-w-56 rounded-2xl object-cover" @error="handlePosterError($event,query.data.value.anime.image)"/><div class="min-w-0"><p class="eyebrow">NOW AVAILABLE</p><h2 class="mt-2 text-3xl font-black">{{ query.data.value.anime.metadata?.title_cn||query.data.value.anime.title }}</h2><p class="muted mt-3 line-clamp-4 max-w-3xl text-sm leading-6">{{ query.data.value.anime.metadata?.summary||query.data.value.anime.summary||'暂无简介' }}</p><div v-if="query.data.value.anime.metadata?.bangumi_id" class="panel-muted mt-5 flex flex-wrap items-center gap-3 p-3"><BookmarkCheck class="text-[var(--brand)]" :size="18"/><label class="text-sm font-bold">Bangumi 看到第 <input v-model.number="progress" class="field mx-1 inline-block h-10 min-h-10 w-20" type="number" min="0"/> 集</label><AsyncButton class="btn btn-secondary ml-auto" :loading="actions.isBusy('sync-progress')" loading-label="同步中…" @click="syncProgress">同步进度</AsyncButton></div></div></div></section><section v-if="selected?.playable" class="panel overflow-hidden bg-black"><video :key="selected.id" controls playsinline class="aspect-video w-full" :src="play(selected.id)"></video><div class="flex items-center justify-between gap-3 bg-[var(--surface-solid)] p-4"><div><p class="font-black">第 {{ selected.episode||'?' }} 集 · {{ selected.name }}</p><p class="muted mt-1 text-xs">{{ selected.overview||'本地媒体文件' }}</p></div><a class="btn btn-secondary shrink-0" :href="play(selected.id)" target="_blank">单独打开</a></div></section><section class="grid gap-3"><article v-for="ep in query.data.value.episodes" :key="ep.id||ep.name" class="panel grid gap-4 p-4 sm:grid-cols-[120px_1fr_auto] sm:items-center" :class="selected?.id===ep.id?'ring-2 ring-[var(--brand)]':''"><div class="grid aspect-video place-items-center overflow-hidden rounded-xl bg-[var(--surface-muted)]"><img v-if="ep.thumbnail" :src="ep.thumbnail" alt="" class="h-full w-full object-cover"/><PlayCircle v-else class="muted"/></div><div><h3 class="font-extrabold">第 {{ ep.episode||'?' }} 集 · {{ ep.name }}</h3><p class="muted mt-1 line-clamp-2 text-sm">{{ ep.overview||'本地媒体文件' }}</p><p v-if="ep.duration" class="muted mt-2 flex items-center gap-1 text-xs"><Clock3 :size="13"/>{{ ep.duration }}</p></div><button v-if="ep.playable" class="btn btn-primary" @click="selected=ep"><PlayCircle :size="17"/>{{ selected?.id===ep.id?'播放中':'播放' }}</button><span v-else class="badge">不可播放</span></article></section></template></div></template>
